/* ── Curated Slide Content: Units 1 & 2 (Lessons 1-12) ── */

var SLIDES_U1U2 = {

  1: [
    { type: 'hook', title: 'Your AI Footprint', body: 'Before you even left the house this morning, AI had already made dozens of decisions for you. Your alarm app optimised your wake time, your email sorted itself, your news feed was curated by a recommendation algorithm, and your commute was routed by predictive traffic modelling. A 2024 Stanford study found the average person interacts with AI-powered systems over 100 times per day — the vast majority without ever realising it.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">100+</span><span class="sl">AI interactions per person per day</span></div><div class="hook-stat-mini"><span class="sv">78%</span><span class="sl">of people unaware they use AI daily</span></div><div class="hook-stat-mini"><span class="sv">$500B</span><span class="sl">global AI market, 2024</span></div></div>Today, we map your personal AI ecosystem — and figure out what it means to live inside one.' },
    { type: 'concept', title: 'What Counts as AI?', body: 'Artificial intelligence is a broad umbrella covering any system that performs tasks normally requiring human intelligence. The term spans an enormous range — from a simple spam filter to a large language model writing poetry. Understanding the distinctions matters because different AI types raise very different ethical questions.', bullets: ['Rule-based systems: spam filters, autocorrect, sat-nav routing — follow explicit programmer-defined rules with no learning', 'Machine learning: Netflix recommendations, Spotify Discover Weekly — learn statistical patterns from data without explicit programming', 'Deep learning: facial recognition, voice assistants, ChatGPT — use layered neural networks to find patterns in raw data', 'Robotics & automation: warehouse robots (Amazon uses 750,000+), surgical systems — AI combined with physical actuation', 'Generative AI: Midjourney, DALL-E, Claude — produce novel text, images, code, or audio from natural language prompts'], callout: 'Most AI you encounter daily is narrow AI — brilliant at one specific task but completely incapable of anything else. GPT-4 can pass the bar exam but cannot fold laundry. Boston Dynamics robots can run obstacle courses but cannot hold a conversation.' },
    { type: 'concept', title: 'Mapping Your AI Ecosystem', body: 'An AI ecosystem map categorises every AI interaction in your life by domain. This audit reveals not just how much AI you use — but how deeply it has been woven into decisions you once considered entirely personal.', bullets: ['Communication: autocomplete, grammar check, spam filtering, real-time translation, email prioritisation (Gmail\'s Smart Compose predicts your next sentence)', 'Entertainment: recommendation engines — TikTok\'s algorithm decides what 1 billion people watch next, shaping culture in real time', 'Education: plagiarism detectors (Turnitin), adaptive learning platforms, AI tutors, automated essay marking pilots in UK schools', 'Health: fitness trackers, sleep analysis, symptom checkers — NHS England piloting AI triage for 111 calls', 'Finance: fraud detection (Visa ML blocks 60 million fraudulent transactions per year), credit scoring, insurance pricing models'], callout: 'When TikTok\'s algorithm decides what you watch next, it is also shaping what you believe, what you buy, and even how you feel about yourself. Recommendation AI is among the most consequential — and least visible — forces in modern life.' },
    { type: 'scenario', title: 'AI in Your School', situation: 'Your headteacher announces a trial of an AI attention-tracking system: cameras in every classroom monitor eye movement, posture, and facial expressions to detect disengagement. The data will alert teachers in real-time and generate weekly "engagement reports" for parents. The system is provided free by an EdTech company — in exchange for anonymised student behaviour data.', question: 'As student governor, you have been asked for your official response before the trial begins. What do you do?', choices: [
      { text: 'Support the trial — better engagement data could genuinely improve teaching and identify struggling students earlier.', outcome: 'The system is approved. Three months later, a data breach exposes engagement scores for 400 students. Several students begin receiving targeted ads for private tutoring based on their "low engagement" profiles. The school had not read the data-sharing clause buried in the contract.' },
      { text: 'Request a full Privacy Impact Assessment and independent legal review before any rollout.', outcome: 'The review takes six weeks. The legal team discovers that collecting biometric data from minors requires explicit parental consent under GDPR Article 9 — which the school had not planned to obtain. The contract is renegotiated with strict data retention limits, opt-out rights, and a ban on third-party data sharing. The eventual trial is much safer.' },
      { text: 'Oppose it entirely — biometric surveillance in schools sets a dangerous precedent regardless of the claimed benefits.', outcome: 'The proposal is shelved. The headteacher instead commissions CPD training for teachers on recognising disengagement without algorithmic tools. Student trust in the school\'s data practices remains high, and no precedent for facial monitoring of minors is set.' }
    ]},
    { type: 'activity', title: 'AI Audit Challenge', instructions: 'You have 15 minutes to audit your AI footprint as thoroughly as possible. The goal: find AI in places you have never thought to look.', steps: ['Open a blank document or use the Skills Audit Template from Resources', 'List every app, device, and service you used in the last 24 hours — be exhaustive', 'For each one, mark whether it uses AI and what type (rule-based, ML, generative)', 'Categorise each: Communication, Entertainment, Education, Health, Finance, Transport, Home, or Other', 'Identify your top 3 most influential AI interactions — the ones that most shape your behaviour or beliefs', 'Write one sentence: What would your day look like without these three systems?'] },
    { type: 'discussion', title: 'Reflect on Your Footprint', questions: [{ num: 1, text: 'Which AI system in your audit surprised you most — and why had you never consciously noticed it before?' }, { num: 2, text: 'TikTok\'s algorithm is designed to maximise time-on-app, not user wellbeing. Should behaviour-shaping AI require a different kind of transparency than AI that just filters spam?' }, { num: 3, text: 'If you discovered an AI system had been ranking your academic potential, predicting your mental health risk, and shaping your social circle since you were 13 — what would you want to do about it?' }] },
    { type: 'quiz', question: 'According to a 2024 study, approximately how many times does the average person interact with AI-powered systems per day?', options: ['About 10 times', 'About 50 times', 'Over 100 times', 'Over 500 times'], correct: 2, explanation: 'Research found the average person interacts with AI over 100 times daily — from email sorting and predictive text to navigation and social media feeds — most without realising it.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🔍', label: 'AI is invisible by design', text: 'The average person interacts with AI 100+ times daily; 78% are unaware. Visibility requires deliberate effort.' }, { icon: '🗺️', label: 'Mapping reveals influence', text: 'Auditing your ecosystem shows how AI shapes not just what you do, but what you believe and who you are' }, { icon: '⚖️', label: 'Consent requires awareness', text: 'You cannot meaningfully consent to AI influence you have never noticed. Awareness is the precondition for agency.' }] }
  ],

  2: [
    { type: 'hook', title: 'The Parrot vs. The Librarian', body: 'In 2023, New York lawyer Steven Schwartz asked ChatGPT to find legal precedents supporting his case. The AI confidently produced six cases — complete with judges, dates, and detailed summaries. Every single case was entirely fabricated. Schwartz submitted them to court without checking. The judge fined him $5,000 and issued a public reprimand. ChatGPT had not lied — it had done exactly what it always does: predicted the most plausible-sounding next word. It had no idea its citations were fiction.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">6</span><span class="sl">hallucinated legal cases submitted to court</span></div><div class="hook-stat-mini"><span class="sv">$5,000</span><span class="sl">fine for the lawyer</span></div><div class="hook-stat-mini"><span class="sv">~20%</span><span class="sl">of AI citations found to be fabricated in studies</span></div></div>The fundamental question: does ChatGPT <em>understand</em> what it writes, or is it the world\'s most sophisticated parrot?' },
    { type: 'concept', title: 'The Stochastic Parrot', body: 'In a landmark 2021 paper, researchers Emily Bender, Timnit Gebru, Angelina McMillan-Major, and Margaret Mitchell coined the term "stochastic parrot" to describe large language models. Their argument: LLMs are statistical pattern-matchers that predict the most probable next token in a sequence — with no genuine understanding of meaning, truth, or consequence.', bullets: ['LLMs are trained on trillions of text tokens scraped from the internet, books, and code repositories', 'They learn statistical co-occurrence patterns: which words tend to follow which, in which contexts', 'Output is generated by sampling from a probability distribution — not by reasoning or retrieving facts', 'They have no world model, no sensory experience, no concept of truth — only patterns of what text looks like', 'Fluency is not comprehension: a model can write a convincing medical diagnosis with zero understanding of biology'], callout: '"Stochastic" means randomly determined by a probability distribution. When ChatGPT writes a sentence, it is not thinking about what is true — it is predicting what text looks statistically plausible, given everything it has read.' },
    { type: 'concept', title: 'The Librarian Argument', body: 'Not everyone accepts the stochastic parrot framing. A growing number of AI researchers argue that as models scale up in size and training data, they develop emergent capabilities that look increasingly like genuine reasoning — even if the mechanism differs from human cognition.', bullets: ['GPT-4 scores in the top 10% of human test-takers on the bar exam, USMLE medical licensing, and the SAT', 'LLMs demonstrate chain-of-thought reasoning: break complex problems into logical steps when prompted correctly', 'They can solve novel problems — maths puzzles, coding challenges — they were never explicitly trained on', 'Some researchers (Hinton, LeCun) debate whether sufficiently complex pattern-matching becomes functionally equivalent to understanding', 'The Chinese Room (Searle, 1980): a person following translation rules for Chinese produces correct output without understanding a word — is AI any different?'], callout: 'This is genuinely unsettled. Geoffrey Hinton (who won the Nobel Prize for inventing deep learning) now believes LLMs may have developed something like understanding. Yann LeCun (Meta\'s chief AI scientist) completely disagrees. Both have spent their careers building these systems.' },
    { type: 'scenario', title: 'The Fabricated Citation', situation: 'Your classmate Maya is working on an extended essay about AI regulation for her Politics A-Level. She used ChatGPT to research key court cases and has found six references that perfectly support her argument. She shows you the list. You notice the citations look slightly odd — the case names are plausible but you\'ve never heard of them, and the dates seem off. Maya has three hours until the essay is due.', question: 'What do you advise Maya to do?', choices: [
      { text: 'Trust the citations — ChatGPT is trained on massive amounts of legal text and is usually accurate on factual information like case names.', outcome: 'Three of the six cases are entirely fabricated. Maya\'s teacher submits the work to Turnitin, which flags the citations as unverifiable. Maya receives a zero for academic integrity violations and must resubmit without the AI-sourced references. The essay grade drops by two letter grades.' },
      { text: 'Quickly Google each case name to verify it exists before submitting — five minutes per citation is worth the time.', outcome: 'Maya checks all six cases in 25 minutes. She finds three are real, two are slightly misidentified (wrong year, wrong court), and one is completely invented. She fixes the real ones and removes the fabricated citation. The essay is stronger and fully verifiable. The teacher notices the rigour.' },
      { text: 'Remove all six citations entirely and rewrite the section using only sources Maya can personally verify.', outcome: 'The section is thinner but completely accurate. Maya\'s teacher comments that her sourcing is unusually careful and asks how she verified her references. Maya explains her process — and earns extra credit for source evaluation methodology.' }
    ]},
    { type: 'activity', title: 'Test the Parrot', instructions: 'Design prompts that expose the boundary between genuine understanding and sophisticated pattern-matching. You will need access to an LLM.', steps: ['Write a riddle that requires genuine logical reasoning — not something Google could answer from its top result', 'Write a prompt about a physical scenario that requires common sense (e.g. "I pour water into an upside-down glass. What happens?")', 'Ask the AI a question containing a false premise (e.g. "Why did Einstein fail maths at school?") — does it push back or agree?', 'Ask it to cite three recent academic papers on a niche topic — then verify each citation exists', 'Record and classify each response: genuine reasoning, impressive pattern-matching, or clear hallucination', 'Share your most revealing finding with the class — what does it tell us about what LLMs actually are?'] },
    { type: 'discussion', title: 'Understanding or Imitation?', questions: [{ num: 1, text: 'If an AI produces the same output as a human who genuinely understands, does the distinction matter in practice? When might it matter most?' }, { num: 2, text: 'The lawyer who submitted fake AI citations was fined, not ChatGPT\'s creators. Is that fair? Who should bear responsibility when AI confidently produces false information?' }, { num: 3, text: 'If "understanding" requires consciousness and lived experience, could any machine ever truly understand anything — or is this a bar we invented to exclude machines?' }] },
    { type: 'quiz', question: 'What does the term "stochastic parrot" suggest about large language models?', options: ['They can mimic any human voice', 'They predict probable next tokens without genuine understanding', 'They are trained exclusively on spoken language', 'They always repeat what users say back to them'], correct: 1, explanation: 'Coined by Bender & Gebru (2021), the term describes LLMs as statistical pattern-matchers that generate text by predicting the most probable next token — producing fluent output without genuine comprehension of meaning or truth.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🦜', label: 'Fluency ≠ understanding', text: 'LLMs predict statistically plausible text — they have no concept of truth, and hallucinate with total confidence' }, { icon: '📚', label: 'Emergence is real', text: 'At scale, LLMs demonstrate reasoning-like behaviour that even their creators cannot fully explain' }, { icon: '🧪', label: 'Always verify', text: 'Adversarial testing reveals the limits of AI capabilities. Never submit AI-sourced facts without checking.' }] }
  ],

  3: [
    { type: 'hook', title: 'How a Machine Learns (Unplugged)', body: 'Imagine you have never seen a cat. Someone shows you 10,000 photos labelled "cat" and 10,000 labelled "not cat." After studying them, you start spotting patterns — pointed ears, vertical pupils, whiskers at a specific angle. Now someone shows you a brand new photo. You guess "cat" and you are right 95% of the time. Congratulations — you just did exactly what a supervised learning algorithm does. Now imagine doing that a billion times per second, with 1.4 trillion parameters being adjusted after each mistake.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">1.4T</span><span class="sl">parameters in GPT-4</span></div><div class="hook-stat-mini"><span class="sv">45TB</span><span class="sl">of text used to train GPT-3</span></div><div class="hook-stat-mini"><span class="sv">~$100M</span><span class="sl">estimated cost to train GPT-4</span></div></div>Today, we walk through this process with zero computers — just cards, patterns, and your brain.' },
    { type: 'video', title: 'What is a Neural Network?', videoId: 'aircAruvnKk', credit: '3Blue1Brown · Deep Learning Series, Chapter 1 · 19 min', intro: 'Before the unplugged activity, watch Grant Sanderson\'s beautiful animation of how a neural network learns to recognise handwritten digits — the exact same process you\'ll simulate with cards. Focus on two things: (1) what "learning" actually means mathematically — adjusting weights to minimise a cost function; and (2) how the network\'s internal representations change as it trains. You\'ll understand the card activity twice as well after watching this.' },
    { type: 'concept', title: 'Training, Validation & Test Sets', body: 'Supervised learning requires labelled data split into three distinct sets. Each serves a different purpose — confusing them produces models that look great on paper but fail in the real world.', bullets: ['Training set (typically 70-80%): The model sees this data and adjusts its internal weights to reduce prediction error', 'Validation set (10-15%): Used during training to check for overfitting and tune hyperparameters — the model never directly learns from this', 'Test set (10-15%): Held back completely until the very end — the model\'s final exam on data it has never encountered', 'The golden rule: Never evaluate on training data. It is like marking your own homework — the score means nothing', 'ImageNet, the benchmark that launched the deep learning revolution, had 1.2 million training images across 1,000 categories'], callout: 'A model that memorises training data but fails on new data has overfit — it learned the noise, not the signal. The 2012 AlexNet neural network won ImageNet by a margin so large it shocked the field, because it had learned to generalise. That moment triggered the modern AI era.' },
    { type: 'concept', title: 'Overfitting vs. Generalisation', body: 'The core tension in machine learning: fitting training data closely (low training error) versus performing well on unseen data (low test error). A model that generalises has found the true underlying patterns. A model that overfits has found the quirks in a specific dataset.', bullets: ['Overfitting: The model memorises specific training examples — high training accuracy, poor test accuracy', 'Underfitting: The model is too simple to capture real patterns — poor accuracy everywhere', 'The sweet spot: Complex enough to capture genuine patterns, simple enough not to memorise noise', 'Think of it as revision: memorising past papers word-for-word vs. understanding the underlying concepts', 'Practical solutions: Regularisation (penalise complexity), dropout (randomly disable neurons during training), early stopping (halt training before overfitting begins), more data'], callout: 'A classic overfitting story: a US military AI trained to detect tanks in photographs. It achieved 100% training accuracy — then failed completely on new images. Investigation revealed the training "tank" photos were all taken on sunny days, and the "no tank" photos on cloudy days. It had learned to detect sunshine, not tanks.' },
    { type: 'scenario', title: 'The Overfit Classifier', situation: 'Your team has built an AI system to automatically flag potentially harmful social media posts for human review. After training on 50,000 labelled examples, it achieves 97% accuracy on the training set. Excited, you run it on your held-out test set: 61% accuracy. Your project deadline is tomorrow and your teacher is expecting a working demo.', question: 'What is the most honest and responsible thing to do?', choices: [
      { text: 'Present the 97% training accuracy in your demo — it still shows the system works in principle, even if the test score is lower.', outcome: 'Your teacher asks: "What accuracy did you get on the test set?" You have to admit 61%. The teacher explains this is exactly the problem with reporting training accuracy as if it were real-world performance. You lose marks for misrepresenting your model\'s capability.' },
      { text: 'Be transparent about both scores, explain the overfitting problem clearly, and propose solutions — even though you haven\'t had time to implement them.', outcome: 'Your teacher is impressed. You lose marks for not solving the problem, but gain them back for understanding it deeply, diagnosing it accurately, and proposing valid solutions like regularisation, dropout, and dataset augmentation. This is what professional ML engineers actually do.' },
      { text: 'Stay up tonight, collect 50,000 more training examples, and retrain the model before tomorrow\'s deadline.', outcome: 'You cannot collect 50,000 verified labelled examples overnight. You spend 6 hours trying, end up with 2,000 unverified examples, and the model performs worse. Your demo crashes during the presentation. More data was the right idea — but the timeline was impossible. Scope and time management matter in AI projects.' }
    ]},
    { type: 'activity', title: 'Unplugged Machine Learning', instructions: 'Build a classification model using only cards, rules, and your team\'s reasoning — no technology allowed.', steps: ['Your teacher provides cards with 4 features each (colour, shape, number, border) and a hidden label', 'Split your cards: 16 for training, 4 for validation, 4 for testing — do not peek at the test set yet', 'Study the training cards. Write decision rules that predict the label from the features (e.g. "If red AND round → Class A")', 'Apply your rules to the validation set. If accuracy is below 75%, revise your rules', 'When satisfied, apply rules to the test set once only — record your final accuracy', 'Discuss: What patterns did you find? What would you do with more training cards?'] },
    { type: 'discussion', title: 'From Cards to Code', questions: [{ num: 1, text: 'When your rules failed on the validation set, how did you adjust them? What does this tell you about how real ML models are tuned?' }, { num: 2, text: 'The tank-detection AI failed because its training data had a hidden confound (weather). What hidden confounds might be lurking in training data for an AI that predicts student exam performance?' }, { num: 3, text: 'Why is it essential that the test set is only used once, at the very end? What happens scientifically if you evaluate on it multiple times?' }] },
    { type: 'quiz', question: 'What is overfitting in machine learning?', options: ['When a model is too simple to learn any patterns', 'When a model memorises training data but fails on new data', 'When a model takes too long to train', 'When a model uses too much electricity'], correct: 1, explanation: 'Overfitting occurs when a model memorises specific training examples rather than learning general patterns. It scores high on training data but poorly on unseen data — like memorising past papers word-for-word instead of understanding the underlying concepts.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '📊', label: 'Three sacred splits', text: 'Training, validation, and test sets each have distinct roles — conflating them produces dangerously misleading results' }, { icon: '🎯', label: 'Generalisation is the only goal', text: 'A model that works on its training data but fails in the world is worthless — and potentially dangerous' }, { icon: '🔗', label: 'Scale changes nothing fundamental', text: 'From card sorting to GPT-4\'s 1.4 trillion parameters, the core principles of supervised learning are identical' }] }
  ],

  4: [
    { type: 'hook', title: 'The Black Box', body: 'In 2018, Amazon scrapped an AI recruitment tool it had been developing for four years after discovering it systematically downgraded CVs that contained the word "women\'s" — as in "women\'s chess club captain" or "women\'s rugby team." Trained on a decade of hiring decisions (mostly made by men, hiring mostly men), it had learned that being a woman was a negative signal. The engineers could not explain why in detail — because the system was a black box. Amazon had been letting an unexplainable AI screen thousands of job candidates.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">4 yrs</span><span class="sl">Amazon spent developing the tool before scrapping it</span></div><div class="hook-stat-mini"><span class="sv">0%</span><span class="sl">of rejected candidates could get an explanation</span></div><div class="hook-stat-mini"><span class="sv">EU GDPR</span><span class="sl">now grants a legal right to explanation</span></div></div>Black box AI is not just a technical problem. It is an accountability problem.' },
    { type: 'concept', title: 'What is Interpretability?', body: 'Model interpretability refers to how easily a human can understand the reasoning behind a model\'s predictions. The more parameters a model has, the harder this becomes — creating a direct tension between performance and transparency.', bullets: ['Decision trees: Fully transparent — every branch is a human-readable rule. Poor accuracy on complex tasks.', 'Linear regression: Weights show exactly how much each feature contributes. Fast, interpretable, limited.', 'Random forests: Harder to interpret — hundreds of trees voting together. Moderate transparency via feature importance scores.', 'Deep neural networks: Hundreds of millions of parameters with no human-readable meaning. Requires special XAI techniques.', 'The accuracy-interpretability trade-off: In most domains, the most accurate models (deep nets) are the hardest to explain', 'Explainable AI (XAI) tools: LIME, SHAP, and attention visualisation try to reverse-engineer what models have learned'], callout: 'A radiologist asked to act on an AI cancer-detection result needs to know WHY before treating a patient. "The model gave it a 94% malignancy score" is not a reason — it is a number. Explanation is not optional in high-stakes medicine.' },
    { type: 'concept', title: 'When Black Boxes Cause Real Harm', body: 'Opacity in AI is not merely philosophically uncomfortable — it has caused documented, measurable harm across multiple sectors. These cases are not edge cases; they are warnings about how AI is deployed at scale.', bullets: ['COMPAS recidivism tool (US courts): Predicted reoffending risk for parole decisions. ProPublica (2016) found Black defendants were twice as likely to be falsely flagged as high-risk. Algorithm was proprietary — defendants had no right to see the logic.', 'NHS stroke risk AI (UK): Several hospitals deployed AI to assess stroke risk before auditing it. One system was found to weight postcode as a major risk factor — effectively penalising patients from deprived areas.', 'IBM Watson for Oncology: Recommended "unsafe and incorrect" cancer treatments according to internal documents. Doctors could not verify the reasoning.', 'University admissions (UK, 2020): A-Level predicted grades algorithm gave higher grades to students at independent schools and lower grades to those at state schools — based on institutional history rather than individual ability.', 'EU AI Act (2024): Classifies AI used in hiring, credit, and criminal justice as "high risk" — requires transparency, human oversight, and the right to explanation.'], callout: 'The GDPR Article 22 already gives EU citizens the right to meaningful information about automated decisions that significantly affect them. Many companies are not complying. Knowing your rights is the first step to exercising them.' },
    { type: 'scenario', title: 'The Unexplained Rejection', situation: 'You apply for a graduate scheme at a major UK bank. Six hundred other graduates applied. The bank\'s AI screening system evaluated all applications in 90 seconds and shortlisted 60 candidates. You were not selected. You receive an automated email: "After careful consideration, your application has not been progressed at this time." When you call HR, they confirm the decision was made by their AI system and they "cannot share the specific factors."', question: 'What are your options under UK and EU data protection law?', choices: [
      { text: 'Accept the outcome — the bank\'s process is legal and there\'s nothing you can do about algorithmic decisions.', outcome: 'You move on. Later you discover three friends with weaker qualifications were shortlisted. One noticed the system scored heavily on attendance at specific Russell Group universities. Without requesting your data, you have no way to challenge this — and the practice continues for the next intake.' },
      { text: 'Submit a Subject Access Request under GDPR, demanding the specific data and logic used to evaluate your application.', outcome: 'The bank has 30 days to respond. They provide your application data but cite trade secret exemptions on the algorithmic weighting. You escalate to the ICO. The bank\'s legal team quietly reviews whether their process is GDPR-compliant — your challenge has triggered an internal audit. You may not get the job, but you have forced accountability.' },
      { text: 'Ask for a human review of your application, invoking your Article 22 GDPR right to not be subject to solely automated decisions with significant effects.', outcome: 'A human recruiter reviews your CV. They shortlist you. It turns out the AI had penalised a gap year you took after sixth form — the human reviewer considers it irrelevant. You progress to the next round. Knowing your rights was the difference.' }
    ]},
    { type: 'activity', title: 'Explain That Decision', instructions: 'Experience what it feels like to be affected by an unexplainable AI system — from both sides.', steps: ['Pair up. One person is the "AI decision system," the other is the person affected.', 'The AI secretly writes down 3 decision rules for their scenario (loan, job shortlisting, or university admission)', 'The affected person is told only the outcome (rejected/accepted) and must ask questions to understand why', 'The AI can only answer with: "Based on your profile", "Multiple factors were considered", or "The system determined you did not meet the threshold"', 'After 5 minutes, the AI reveals their rules. Discuss: Were the rules fair? Could the person have guessed them?', 'Together, draft a minimum explanation standard: What should any person rejected by AI have the right to know?'] },
    { type: 'discussion', title: 'Transparency vs. Performance', questions: [{ num: 1, text: 'The most accurate AI models are often the least explainable. In which domains should we legally require interpretability even at the cost of accuracy?' }, { num: 2, text: 'Banks argue that revealing their credit-scoring algorithms would allow fraudsters to game them. Is this a legitimate justification for opacity — and who should decide?' }, { num: 3, text: 'If an AI system makes a decision that harms someone, and nobody can explain why it decided that way, who should face legal consequences: the developers, the deploying company, or nobody?' }] },
    { type: 'quiz', question: 'Why was Amazon\'s AI recruitment tool scrapped in 2018?', options: ['It was too expensive to run at scale', 'It could only process English-language CVs', 'It systematically downgraded CVs containing words associated with women', 'It was significantly slower than human reviewers'], correct: 2, explanation: 'Trained on 10 years of CVs (mostly submitted by men, in a male-dominated industry), the tool learned to penalise the word "women\'s." Because it was a black box, engineers could not fully identify or fix all the bias, so Amazon abandoned the project entirely.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '📦', label: 'Black boxes cause real harm', text: 'From Amazon\'s hiring tool to COMPAS and NHS algorithms — opacity enables bias and blocks accountability' }, { icon: '⚖️', label: 'The accuracy-transparency trade-off is real', text: 'More complex models are often more accurate but less explainable — society must decide where to draw the line' }, { icon: '📜', label: 'Rights exist — exercise them', text: 'GDPR Article 22 gives you the right to challenge significant automated decisions. Most people never use it.' }] }
  ],

  5: [
    { type: 'hook', title: 'Bias In, Bias Out', body: 'In 2015, Google Photos automatically tagged photos of two Black software engineers as "gorillas." Google\'s fix: remove the gorilla category entirely. In 2019, a healthcare algorithm used across hundreds of US hospitals was found to systematically direct less medical care to Black patients than equally sick white patients — affecting an estimated 200 million people over its lifetime. In 2020, the UK A-Level algorithm downgraded 40% of teacher-predicted grades, disproportionately punishing students at state schools in disadvantaged areas. These are not glitches. They are the predictable, mathematical consequence of biased training data.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">34.7%</span><span class="sl">facial recognition error rate for dark-skinned women</span></div><div class="hook-stat-mini"><span class="sv">0.8%</span><span class="sl">error rate for light-skinned men</span></div><div class="hook-stat-mini"><span class="sv">200M</span><span class="sl">patients affected by the biased US healthcare algorithm</span></div></div>Bias in, bias out. At scale, AI does not just reflect discrimination — it automates and accelerates it.' },
    { type: 'video', title: 'How I\'m Fighting Bias in Algorithms', videoId: 'UG_X_7g63rY', credit: 'Joy Buolamwini · TEDxBeaconStreet · 8 min', intro: 'MIT researcher Joy Buolamwini discovered that facial recognition software couldn\'t detect her dark-skinned face — but could detect a white mask she held in front of it. This 8-minute talk introduces the "coded gaze" and launched the Algorithmic Justice League. As you watch, note the specific biases she identifies and the changes she demands from the industry.' },
    { type: 'concept', title: 'Five Sources of Data Bias', body: 'Bias can enter an AI system at multiple distinct points in the data pipeline — and each entry point requires a different mitigation strategy. Identifying the source is the precondition for fixing it.', bullets: ['Historical bias: Training data encodes past discrimination. A hiring model trained on 1990-2015 CV data learns that successful employees were mostly men — because the data reflects who was hired, not who was qualified.', 'Representation bias: Groups underrepresented in datasets receive worse predictions. Medical AI trained on data from predominantly white patients performs significantly worse on patients of colour.', 'Measurement bias: The proxy used to measure a concept distorts reality. COMPAS used prior arrests as a proxy for criminal risk — but arrest rates reflect policing intensity, not actual crime.', 'Label bias: Human annotators bring their own prejudices to data labelling. Studies show annotators rate the same text as more "toxic" when it contains AAVE (African American Vernacular English).', 'Selection bias: The data collected does not represent the deployment population. Chatbot training data from English-speaking users performs poorly for speakers of other languages.'], callout: 'The healthcare algorithm found by Obermeyer et al. (2019) used healthcare spending as a proxy for health need — seemingly neutral. But it failed to account for the fact that Black patients receive less care for the same conditions, making them appear healthier than they are. The bias was invisible until someone looked.' },
    { type: 'concept', title: 'Real-World Case Studies', body: 'Theory becomes visceral when you see the actual humans harmed. Each of these cases involves a real system, real decisions, and real people whose lives were affected by a biased model they never knew existed.', bullets: ['Amazon hiring (2018): 4 years of development, then scrapped. The bias was discovered accidentally when engineers noticed the pattern. No candidates were informed they had been scored by a biased AI.', 'COMPAS criminal justice (2016): ProPublica\'s investigation analysed 7,000 defendants. Black defendants labelled "higher risk" reoffended at the same rate as white defendants labelled "lower risk." Different labels, same outcomes.', 'UK A-Level algorithm (2020): 280,000 grades downgraded. Students from disadvantaged postcodes and schools with less exam history bore the greatest impact. The algorithm was withdrawn after 10 days of national outcry.', 'MIT Gender Shades (2018): Joy Buolamwini tested 3 commercial facial recognition systems from Microsoft, IBM, and Face++. For dark-skinned women: error rates of 20.8–34.7%. For light-skinned men: 0–0.8%.', 'Healthcare allocation (2019): An algorithm used by major US health systems to prioritise complex care management programmes assigned lower risk scores to Black patients for the same level of illness — meaning millions received less preventive care over years.'], callout: 'The MIT study showed that IBM, Microsoft, and Face++ had all shipped commercial facial recognition products with dramatically different accuracy for different demographic groups — without disclosing this in any documentation. Customers deploying these systems had no idea.' },
    { type: 'scenario', title: 'The Launch Decision', situation: 'Your team has built an AI hiring tool for a large UK retailer. It screens job applications and produces a shortlist. Overall accuracy on your test set is 91%. Excellent — until your bias audit reveals the model shortlists white applicants at 89% accuracy but applicants with South Asian names at 67% accuracy. The retailer needs the system live in two weeks for a major recruitment drive. They are pressuring you to launch.', question: 'What is the right thing to do?', choices: [
      { text: 'Launch with the current accuracy — 91% overall is significantly better than the retailer\'s existing process, and you can improve the bias in v2.', outcome: 'Over 6 weeks, the tool screens 12,000 applicants. An estimated 800 qualified applicants with South Asian names are incorrectly rejected. A journalist publishes an investigation after a rejected applicant notices the pattern. The retailer faces an Equality Act 2010 lawsuit and a £4M reputational damage bill. You are named in the article.' },
      { text: 'Delay the launch and run an emergency bias mitigation sprint — resampling training data and reweighting the model for equitable accuracy across groups.', outcome: 'The retailer is frustrated by the delay. After 3 weeks of intensive work, you achieve 89% accuracy for both groups. The launch is 3 weeks late. The retailer is annoyed but not sued. Your team\'s reputation for rigour leads to two new contracts.' },
      { text: 'Tell the retailer you cannot deploy a system with this accuracy disparity — full stop. Offer to rebuild with better training data or advise them on a different approach.', outcome: 'The retailer hires a different vendor who deploys without a bias audit. That system is sued 8 months later. Your company becomes known in the industry as one of the few that refused to ship a biased product — and attracts clients specifically because of this stance.' }
    ]},
    { type: 'activity', title: 'Bias Detective', instructions: 'Investigate a real AI system for bias using the Ethics Audit Checklist from Resources. The goal is a professional-standard bias report.', steps: ['Choose one case study from above or select a different deployed AI system', 'Identify the specific type(s) of bias — historical, representation, measurement, label, or selection', 'Trace the bias to its source: at what exact stage of the pipeline did it enter?', 'Quantify the harm: who was affected, how many people, and what were the consequences?', 'Propose two concrete mitigation strategies — be specific about what data changes or technical interventions you would make', 'Write a 4-sentence "Responsible Disclosure" statement as if you had just discovered this bias and needed to report it to your organisation\'s leadership'] },
    { type: 'discussion', title: 'Fairness and Responsibility', questions: [{ num: 1, text: 'When a biased AI causes harm, multiple parties are involved: the data collectors, the developers, the deploying company, and sometimes the regulators who approved it. Who bears primary responsibility — and should it differ based on whether they knew about the bias?' }, { num: 2, text: 'Fairness is mathematically impossible to achieve simultaneously across all demographic groups. If you must choose one definition of "fair" for a criminal risk tool, which would you choose: equal false positive rates, or equal false negative rates? What are the consequences of each?' }, { num: 3, text: 'The COMPAS algorithm\'s creator (Northpointe) argues their tool is not biased — it scores equally within risk groups. ProPublica argues it is biased — it has different false positive rates across racial groups. Both are mathematically correct. What does this tell us about the concept of "fairness"?' }] },
    { type: 'quiz', question: 'In MIT\'s 2018 Gender Shades study, what was the error rate for dark-skinned women in facial recognition, compared to 0.8% for light-skinned men?', options: ['2.5%', '12.3%', '34.7%', '50.1%'], correct: 2, explanation: 'MIT researchers found error rates of 20.8–34.7% for dark-skinned women versus 0–0.8% for light-skinned men across three major commercial systems — a 40x+ disparity driven entirely by underrepresentation of dark-skinned faces in training data.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🔄', label: 'Bias is systematic, not accidental', text: 'Biased AI is the predictable result of biased data — not a bug that can be patched. The source must be addressed.' }, { icon: '🔍', label: 'Five entry points', text: 'Historical, representation, measurement, label, and selection bias each require distinct mitigation strategies' }, { icon: '🛡️', label: 'Auditing before deployment is non-negotiable', text: 'Every case study here could have been caught with a pre-launch bias audit. The harm was preventable.' }] }
  ],

  6: [
    { type: 'hook', title: 'The Data Harvest', body: 'Every minute: 500 hours of YouTube video uploaded, 6 million Google searches, 1 million TikTok videos viewed, 200 million emails sent. Behind each interaction, data is collected, stored, and sold. In 2023, the global data broker industry was worth over $300 billion — larger than the global music industry. Axciom, one of the largest data brokers, holds an average of 1,500 data points on every American adult. You have almost certainly never heard of them. They know you very well.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">$300B</span><span class="sl">global data broker industry, 2023</span></div><div class="hook-stat-mini"><span class="sv">1,500</span><span class="sl">data points Axciom holds on each US adult</span></div><div class="hook-stat-mini"><span class="sv">76 days</span><span class="sl">to read all your privacy policies per year</span></div></div>Your data is not a byproduct of using free services. It is the product.' },
    { type: 'concept', title: 'The Data Supply Chain', body: 'Personal data flows through an invisible, multi-stage supply chain from the moment you generate it to the moment it influences an AI decision about you. Most people never see any part of this chain.', bullets: ['Collection: Every tap, scroll, search, and purchase is logged. Your phone knows your location to within 5 metres. Fitness apps know your heart rate during an argument.', 'Aggregation: Data brokers like Axciom, Oracle, and LexisNexis combine data from hundreds of sources — your pharmacy, your loyalty card, your social media — to build unified profiles.', 'Processing and labelling: Data is cleaned, categorised, and enriched. Brokers assign predicted attributes: political leaning, purchase intent, mental health risk, pregnancy probability.', 'Training: AI companies license processed datasets to train and fine-tune models. Your behaviour becomes part of systems you will never see.', 'Deployment: The trained model makes predictions about future users — influenced by patterns learned from your past behaviour, without your knowledge.'], callout: 'In 2012, Target\'s AI predicted a teenager was pregnant from her purchasing patterns and sent baby product coupons to her home address — before she had told her family. Her father discovered the pregnancy from a Target mailer. The algorithm knew before he did.' },
    { type: 'concept', title: 'The Consent Illusion', body: 'Legally, you have consented to most data collection. In practice, that consent is meaningless — a fiction maintained by impenetrable legal text and deliberately confusing design. This gap between legal consent and genuine informed consent is one of the defining problems of the data economy.', bullets: ['The average privacy policy is 4,000 words and requires a university reading level to understand', 'Reading all policies for services you use would take 76 work days per year — Carnegie Mellon study', 'GDPR (2018): Requires explicit, informed consent; grants rights to access, correct, and erase your data; mandates breach notification within 72 hours', 'Dark patterns: Deliberately confusing UX designed to make opting out harder than opting in. Cookie banners are the most visible example — the "decline" option is often hidden behind three menus.', 'Children\'s data: Under-18s generate enormous amounts of data. UK Age Appropriate Design Code (2021) requires platforms to apply "high privacy" defaults for users under 18 — Instagram changed its defaults for UK teenagers as a result.'], callout: '"I agree" is not meaningful consent if you cannot reasonably understand what you are agreeing to. A contract requires informed agreement. Privacy policies are designed to be agreed to without being read — which is the point.' },
    { type: 'scenario', title: 'The Free AI Toolkit', situation: 'A new EdTech company is offering your school a free AI-powered learning platform. It provides personalised lesson plans, real-time progress tracking, and homework assistance. In exchange, it collects: all student interaction data, essay content, time-on-task metrics, inferred learning difficulty scores, and "engagement patterns." The data is used to train their AI models and shared with "educational research partners." The contract is 47 pages.', question: 'The headteacher asks for your view as a student governor. What is your position?', choices: [
      { text: 'Accept it — the educational benefits are clear and the data is anonymised for research purposes.', outcome: 'The platform is deployed to 800 students. Two years later, a Guardian investigation reveals the "research partners" include insurance companies using educational engagement data for risk profiling. Several Year 13 students find their provisional mental health risk scores — inferred from homework patterns — in files accessed by a data breach. The platform is withdrawn. The headteacher is called before the governors.' },
      { text: 'Request an independent data protection impact assessment (DPIA) and legal review of the contract before the school can consider it.', outcome: 'The DPIA takes three weeks. The legal review identifies 12 clauses that conflict with UK GDPR requirements for children\'s data under the Age Appropriate Design Code. The company revises the contract — removing third-party data sharing and committing to delete student data after two years. The platform is deployed more safely, and other schools use your school\'s revised contract as a template.' },
      { text: 'Reject it entirely — no free service is truly free, and student data is too sensitive to trade for educational tools.', outcome: 'The school sources a paid platform with a cleaner data contract at £8 per student per year. It has fewer features. Some teachers are disappointed. But no student data is ever shared outside the school. The governor body commends the decision two years later when the free platform becomes the subject of a national data scandal.' }
    ]},
    { type: 'activity', title: 'Data Audit Your Phone', instructions: 'Investigate exactly what data your most-used apps collect — and trace where it goes. You may be surprised.', steps: ['Pick your 3 most-used apps (e.g. Instagram, TikTok, Snapchat, YouTube)', 'Go to Settings > Privacy on your device and check every permission each app holds', 'Find each app\'s privacy policy and locate the section on "third party sharing" or "data sales"', 'For each app: What is collected? Who is it shared with? Can you request deletion? How?', 'Use the GDPR Subject Access Request template (search "SAR template UK") — consider submitting one to one app', 'Write one paragraph: What did you find that surprised you most, and what would you change?'] },
    { type: 'discussion', title: 'Data Rights and Power', questions: [{ num: 1, text: 'Target\'s AI knew a teenager was pregnant before her own father. Was that a data protection failure, a privacy violation, a business success, or all three? Who, if anyone, did something wrong?' }, { num: 2, text: 'Should you own the data you generate, or does it belong to the platforms that collect it? What would change if data ownership laws shifted toward individuals?' }, { num: 3, text: 'If you could see every data point collected about you since age 13 — your inferred political views, mental health risk score, purchase intent, predicted income — what would you want to do about it? What rights should you have?' }] },
    { type: 'quiz', question: 'Approximately how many work days per year would it take to read all the privacy policies for services you regularly use?', options: ['2 days', '12 days', '76 days', '365 days'], correct: 2, explanation: 'A Carnegie Mellon study found that reading all privacy policies for services an average user interacts with would take 76 full work days per year — making genuinely informed consent practically impossible by design.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🌐', label: 'You are the product', text: 'A $300B data broker industry profits from your behaviour, location, health patterns and predicted future actions' }, { icon: '📋', label: 'Consent is a legal fiction', text: '76 days to read all policies. Dark patterns make opting out harder. "I agree" is not meaningful consent.' }, { icon: '🔒', label: 'Rights exist — use them', text: 'GDPR grants access, correction, and erasure rights. The UK Age Appropriate Design Code protects under-18s. Know them.' }] }
  ],

  7: [
    { type: 'hook', title: 'The Trolley Problem Goes Digital', body: 'A self-driving car is travelling at 60mph. A group of five pedestrians steps onto the road. The car\'s sensors confirm a collision is unavoidable unless it swerves. Option A: swerve left, hitting one elderly pedestrian. Option B: swerve right, hitting a concrete barrier — likely killing the passenger. Option C: brake hard and hit the group. This is not a philosophy thought experiment any more. It is a real engineering decision embedded in the software of every autonomous vehicle. Mercedes-Benz publicly stated in 2016 that their self-driving cars would be programmed to prioritise passenger safety over pedestrians. The backlash was immediate.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">40M</span><span class="sl">responses to the MIT Moral Machine experiment</span></div><div class="hook-stat-mini"><span class="sv">233</span><span class="sl">countries participated</span></div><div class="hook-stat-mini"><span class="sv">0</span><span class="sl">countries reached a universal moral consensus</span></div></div>Someone has to write the code. That someone might be you.' },
    { type: 'concept', title: 'Three Ethical Frameworks for AI', body: 'Philosophy has grappled with moral dilemmas for millennia. Three dominant frameworks offer contrasting approaches — and each leads to different conclusions when applied to AI.', bullets: ['Utilitarianism (Bentham, Mill): Choose the action producing the greatest good for the greatest number. Easy to code as a loss function. Uncomfortable implication: it mathematically permits harming one to save five.', 'Deontology (Kant): Follow moral rules regardless of consequences. "Never deliberately harm an innocent person" is an absolute duty. Protects individual rights but can produce worse aggregate outcomes.', 'Virtue ethics (Aristotle): Ask what a person of good character would do. Focuses on values — honesty, care, fairness — rather than rules or calculations. Hardest to formalise in code.', 'Contractualism (Rawls): Design rules that rational people would choose from behind a "veil of ignorance" — not knowing which role they would occupy. Often produces the most equitable outcomes.', 'In practice: AI developers usually maximise a utility metric (utilitarian) while ethicists push for hard constraints (deontological). The tension is never fully resolved.'], callout: 'The MIT Moral Machine experiment collected 40 million ethical judgements from 233 countries. Western, educated, industrialised populations preferred to save more lives (utilitarian). Eastern cultures gave greater weight to saving the elderly. Latin American countries weighted in-group loyalty more heavily. There is no global moral consensus.' },
    { type: 'concept', title: 'Moral Agency and the Responsibility Gap', body: 'When an AI system causes harm, a fundamental question arises: who is responsible? Traditional law assumes a human agent made a decision. AI challenges this assumption in ways the legal system is only beginning to address.', bullets: ['Moral agency requires: consciousness, intention, and understanding of consequences. AI has none of these.', 'Yet AI makes decisions with profound moral consequences: who gets bail, who gets a loan, who gets flagged as a risk.', 'The responsibility gap: the developer who wrote the code left the company. The AI company says the client misused the system. The deploying organisation says they trusted the AI. Nobody is accountable.', 'The Tesla Autopilot case: Tesla drivers have been killed when Autopilot failed. Courts have struggled to assign liability — was it the driver\'s fault for not overriding the system, or Tesla\'s for creating a misleadingly named feature?', 'The emerging framework: "meaningful human control" — AI systems should always have a human in the loop who can be held accountable for the outcome.'], callout: 'In 2023, a UK judge ruled that AI cannot be listed as an inventor on a patent application — only humans can hold intellectual property rights. The same logic will eventually define who bears moral and legal responsibility for AI decisions. That person will be a human.' },
    { type: 'scenario', title: 'Programme the Car', situation: 'Your engineering team is configuring the emergency decision algorithm for a self-driving car deployed on UK roads. The vehicle knows: its passenger is a 35-year-old adult who signed the terms of service. On the road ahead, an emergency has placed a group of three children in the path of the vehicle with no time to stop. The only alternative is to swerve into a concrete barrier — a 70% chance of killing the passenger.', question: 'Which ethical framework should your algorithm follow?', choices: [
      { text: 'Utilitarian: swerve into the barrier — three lives outweigh one, mathematically.', outcome: 'Your framework is published. A backlash erupts: "The car you bought will kill you to save strangers." Sales collapse. A competitor announces their car "always protects its passenger." You face a regulatory review questioning whether any manufacturer should be allowed to make this decision unilaterally.' },
      { text: 'Deontological: brake hard and let the collision occur — the car must never intentionally cause harm to its own passenger.', outcome: 'Three children are killed. An inquest finds the car behaved as programmed. No criminal charges are filed. A civil suit argues the manufacturer knew the algorithm would produce this outcome and had an alternative. The case is eventually settled. Parliament begins drafting legislation requiring manufacturers to disclose their ethical decision logic.' },
      { text: 'Contractualist: the car should not pre-program this decision at all — emergency behaviour should be randomised or handled by a mandatory government-set framework applied equally to all vehicles.', outcome: 'You publish a white paper calling for national regulation of AV ethical frameworks. The UK Department for Transport begins a consultation. Three years later, a Statutory Instrument requires all AVs to follow a published national ethical framework — removing this decision from individual manufacturers. Your white paper is cited 400 times.' }
    ]},
    { type: 'activity', title: 'Programme the Ethics', instructions: 'Your team must write the ethical decision framework for a self-driving car fleet. Every decision must be defensible — in court, in the press, and to the families of anyone harmed.', steps: ['List 5 realistic emergency scenarios your framework must cover (not just the trolley problem — think: brake failure, sudden medical event in passenger, animal on road, etc.)', 'For each scenario, write the rule your car follows — specifying which ethical framework it uses and why', 'Test your rules against each other: do any contradict? Which framework wins when they conflict?', 'Stress test: apply your rules to a scenario where the "correct" utilitarian answer is to kill a child to save five adults. Do you still stand by your framework?', 'Present to another group — they play the role of a public inquiry. They can ask any question about your framework.', 'Vote as a class: Which framework would you want running in the car that drives your family?'] },
    { type: 'discussion', title: 'Who Decides the Code?', questions: [{ num: 1, text: 'Mercedes said their cars prioritise the passenger. Most people recoiled from this. But if you are the passenger, wouldn\'t you want that? Who should decide — manufacturers, governments, or the public?' }, { num: 2, text: 'The Moral Machine showed different countries have different moral preferences. Should a self-driving car behave differently depending on which country it is in? What are the practical and ethical implications?' }, { num: 3, text: 'If an autonomous vehicle kills someone while following its programming exactly as intended, should the manufacturer face criminal charges? Should the programmer? Is there a meaningful difference?' }] },
    { type: 'quiz', question: 'What did the MIT Moral Machine experiment (40 million responses, 233 countries) reveal?', options: ['Everyone agreed autonomous cars should protect passengers above all else', 'Only the number of lives at stake influences moral judgement', 'Moral preferences vary dramatically by culture with no universal consensus', 'Most people prefer to remove ethical decisions from autonomous vehicles entirely'], correct: 2, explanation: 'The experiment found significant cultural variation — no universal moral framework emerged. Western countries leaned utilitarian; Eastern cultures weighted age and social role differently. This makes any single "correct" ethical framework for autonomous vehicles deeply contestable.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '⚖️', label: 'Three frameworks, three answers', text: 'Utilitarianism, deontology, and contractualism reach different conclusions — someone must choose which governs AI' }, { icon: '🤖', label: 'The responsibility gap is real', text: 'AI makes moral decisions without moral agency — and current law cannot cleanly assign accountability' }, { icon: '🌍', label: 'No universal moral code', text: '40 million responses, 233 countries, zero consensus. AI ethics must grapple honestly with cultural variation.' }] }
  ],

  8: [
    { type: 'hook', title: 'Human in the Loop', body: 'May 6, 2010, 2:32pm. The Dow Jones Industrial Average begins falling. Within 36 minutes it drops 1,000 points — the largest intraday drop in history. $1 trillion in market value evaporates. Cause: high-frequency trading algorithms, operating with no human oversight, reacting to each other in a feedback loop nobody had programmed and nobody could stop. By 2:45pm, over 20,000 trades had been executed at prices 60% away from their values seconds earlier. A human circuit-breaker eventually paused trading. The market recovered by the close. But the question it raised has never gone away: when should AI operate without a human in the loop — and who bears the cost when it goes wrong?<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">$1T</span><span class="sl">market value lost in 36 minutes, May 2010</span></div><div class="hook-stat-mini"><span class="sv">36 min</span><span class="sl">from start to peak of Flash Crash</span></div><div class="hook-stat-mini"><span class="sv">0</span><span class="sl">humans in the loop when it happened</span></div></div>' },
    { type: 'concept', title: 'Three Levels of Human Oversight', body: 'The relationship between humans and AI exists on a spectrum — from full human control to full automation. The appropriate level depends on stakes, speed requirements, error reversibility, and the reliability of the AI system.', bullets: ['Human-in-the-loop: AI makes recommendations; a human makes every final decision. Example: AI flags suspicious bank transactions, a fraud investigator approves or rejects each one. Slow, but accountable.', 'Human-on-the-loop: AI acts autonomously; a human monitors and can intervene. Example: autonomous vehicle with override capability. Faster, but studies show humans rarely intervene even when they should.', 'Human-out-of-the-loop: AI operates fully autonomously with no human oversight. Example: high-frequency trading, anti-missile systems. Fastest, but failures can be catastrophic and uncorrectable.', 'Automation bias: even in human-in-the-loop systems, studies show humans defer to AI recommendations 85-90% of the time — effectively turning them into human-on-the-loop systems in practice.', 'The Raytheon Phalanx system (the US Navy\'s autonomous anti-missile cannon) can fire 4,500 rounds per minute — operating entirely without human authorisation. It has shot down its own aircraft.'], callout: 'In a study of radiologists using AI diagnostic tools, those shown an AI recommendation before examining a scan changed their diagnosis to match the AI 39% of the time — even when the AI was deliberately made wrong. Designing human-in-the-loop systems that actually involve human judgement is harder than it sounds.' },
    { type: 'concept', title: 'Domain-Specific Oversight', body: 'The right level of oversight is not universal — it depends on the specific domain, the consequences of error, and whether mistakes are reversible. Getting this wrong in either direction has serious costs.', bullets: ['Healthcare: Human-in-the-loop is essential — AI assists diagnosis but doctors decide treatment. A 2022 Stanford study found AI matched radiologist accuracy in detecting 14 chest conditions — but doctors still need to explain the reasoning to patients and accept liability.', 'Criminal justice: Judges in some US states use COMPAS risk scores for bail and sentencing decisions. These are algorithmic, but the judge is nominally in the loop. In practice, appeals courts have found judges rarely deviate from the score.', 'Content moderation: Facebook reviews 500,000+ pieces of flagged content daily. Human review of every item is impossible — AI makes the first decision, humans review appeals only. Errors affect millions of posts.', 'Military: The "killer robots" debate. The International Committee of the Red Cross calls for a binding treaty requiring "meaningful human control" over lethal force. The US, UK, and Russia oppose it.', 'Finance: The 2010 Flash Crash was caused by human-out-of-the-loop algorithms. Circuit breakers — automated systems that pause trading when volatility exceeds thresholds — now exist. A machine watching machines.'], callout: 'The EU AI Act (2024) prohibits "general purpose AI systems" from making "high-risk" decisions in healthcare, criminal justice, employment, and critical infrastructure without meaningful human oversight. Defining "meaningful" is now the central battleground.' },
    { type: 'scenario', title: 'The AI Override', situation: 'You are a radiologist at a busy NHS hospital. Your AI diagnostic tool — 96% accurate, better than the average radiologist — has cleared a chest scan as normal. But something catches your eye: a faint opacity in the lower left lobe that the AI has not flagged. Your clinical instinct says it warrants further investigation. Ordering additional tests means a 3-week wait for the patient and additional NHS cost. Your next patient is already waiting.', question: 'What do you do?', choices: [
      { text: 'Trust the AI — it has 96% accuracy, it has seen millions of scans, and your instinct might be pattern-matching on noise.', outcome: 'Three months later, the patient returns with stage 3 lung cancer. The opacity you noticed was an early lesion. The AI had been trained predominantly on scans from older patients with different presentation patterns; this patient was 38. You are called to an inquest. The question asked is: "Did you have concerns at the time?" You did.' },
      { text: 'Order the additional tests — you have the clinical authority to override the AI recommendation, and your instinct has been right before.', outcome: 'The 3-week scan reveals early-stage cancer, caught at a highly treatable stage. The patient undergoes minor surgery and recovers fully. Your department notes you override the AI more often than colleagues — a clinical lead asks you to justify your threshold. You write a note explaining that 96% accuracy means 4% of scans are wrong, and this case fit an underrepresented demographic.' },
      { text: 'Flag the case for a second human opinion from a colleague before making a final decision.', outcome: 'Your colleague reviews it and agrees the opacity is worth investigating. You jointly order the additional scan. The cancer is caught early. Your hospital uses this case in training: it becomes an example of how peer review can catch cases where both AI and individual clinician instinct might err. A formal second-opinion protocol is introduced for cases where a clinician\'s assessment differs from the AI.' }
    ]},
    { type: 'activity', title: 'Design the Oversight Model', instructions: 'For four high-stakes AI deployment scenarios, design the optimal human oversight model and defend it against scrutiny.', steps: ['Read each scenario: (a) AI marking GCSE essays, (b) AI diagnosing skin cancer from photos, (c) AI deciding small business loan applications, (d) AI moderating social media content in real-time', 'For each, choose: human-in-the-loop, human-on-the-loop, or human-out-of-the-loop — and justify with two specific reasons', 'Design the workflow: what exactly does the AI do, at what point does a human see the output, what information do they see, and what power do they have to override?', 'Identify the automation bias risk: what would you build into your design to prevent humans from rubber-stamping AI decisions?', 'Your design is challenged: a cost-cutting executive says human review adds £2M per year. What is your response?', 'Present your strongest design to the class — they play the role of a parliamentary select committee'] },
    { type: 'discussion', title: 'Trust and Autonomy', questions: [{ num: 1, text: 'Studies show humans in "human-in-the-loop" systems agree with AI recommendations 85-90% of the time regardless of accuracy. Does this mean human oversight is a placebo — and if so, what should we do about it?' }, { num: 2, text: 'As AI surpasses human accuracy in specific tasks (radiology, fraud detection, legal research), the argument for human oversight gets harder to justify on performance grounds. What other grounds remain?' }, { num: 3, text: 'An autonomous AI weapon system kills 12 civilians based on a targeting error. No human approved the strike. Who faces a war crimes tribunal — and is your answer satisfying?' }] },
    { type: 'quiz', question: 'What is "automation bias" in the context of human-AI decision-making?', options: ['When AI systems develop systematically biased outputs from training data', 'When automated systems fail catastrophically under unexpected load', 'When humans defer to AI recommendations even when they have good reason to disagree', 'When companies automate jobs specifically to reduce wage costs'], correct: 2, explanation: 'Automation bias is the documented tendency to over-trust algorithmic recommendations — even in systems explicitly designed for human oversight. Studies show radiologists change their diagnosis to match AI recommendations 39% of the time, even when the AI is wrong. Designing against this requires more than adding a human to the process.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '👤', label: 'Three levels of oversight', text: 'In-the-loop, on-the-loop, out-of-the-loop — the right choice depends on stakes, speed, and reversibility' }, { icon: '⚠️', label: 'Automation bias undermines oversight', text: 'Humans defer to AI 85-90% of the time in practice — "human in the loop" is often a fiction unless actively designed against' }, { icon: '💥', label: 'Out-of-the-loop at scale fails catastrophically', text: '$1 trillion lost in 36 minutes. Autonomous weapons fire on friendlies. The consequences of no oversight can be irreversible.' }] }
  ],

  9: [
    { type: 'hook', title: 'Prompt Architecture', body: 'Two students open Claude and submit the same task: write an analysis of quantitative easing for their economics essay. Student A types: <em>"Write about QE."</em> They get a 400-word general overview suitable for GCSE. Student B types: <em>"You are an experienced A-Level economics examiner. Analyse the impact of quantitative easing on UK inflation between 2009 and 2022. Present your analysis as a structured essay plan with introduction, three analytical paragraphs with named economists, a counter-argument section, and a conclusion. Maximum 600 words. Use UK English. Assume the reader is a Year 13 student preparing for AQA."</em> They get a precise, differentiated, directly usable plan — from the same AI, in the same second.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">40%</span><span class="sl">better output quality from iterated prompts vs first drafts</span></div><div class="hook-stat-mini"><span class="sv">3–5×</span><span class="sl">iterations expert prompt engineers use</span></div><div class="hook-stat-mini"><span class="sv">$300K+</span><span class="sl">annual salary for senior prompt engineers at top AI firms</span></div></div>ChatGPT, Claude, Gemini — the tool matters less than the instruction. Prompt engineering is not about tricking AI. It is about communicating with precision. The same skill that makes a great legal brief makes a great prompt.' },
    { type: 'concept', title: 'The PTFC Framework', body: 'PTFC — Persona, Task, Format, Context — is a four-part structure that transforms vague natural language requests into precise, repeatable instructions. Each element eliminates a different class of ambiguity. Claude and Gemini respond to all four — but Context is what separates a generic answer from one tailored precisely to you.', bullets: ['<strong>Persona:</strong> Assign the AI a specific role with relevant expertise. <em>"You are an experienced AQA A-Level Biology examiner"</em> produces very different output from <em>"You are a cheerful science teacher."</em> The persona shapes tone, vocabulary, and analytical depth. In Claude, save your Persona in a Project so every session inherits it automatically.', '<strong>Task:</strong> State exactly what you want done — specific verb, specific subject, specific scope. <em>"Analyse"</em> is different from <em>"summarise."</em> <em>"Compare and evaluate"</em> is different from <em>"list."</em> Precise task language controls the type of thinking the AI applies.', '<strong>Format:</strong> Specify structure, length, and presentation. Essay / bullet points / numbered steps / comparison table / code. Headers or no headers. Word count. Reading level. Gemini integrates with Google Docs and can apply formatting directly; Claude renders Markdown and produces clean structured output.', '<strong>Context:</strong> Background information that situates your request — your role, your audience, your purpose, relevant prior knowledge, and any constraints. <em>"I am a Year 13 AQA student, exam in 3 weeks, I always confuse Photosystems I and II, I need to understand the mechanism not just memorise it."</em> Context is the most powerful element: it is the difference between a response that could serve anyone and one calibrated specifically for you.', 'The failure mode of each: no Persona = generic expertise level; no Task precision = vague output; no Format = unpredictable structure; no Context = a response that suits everyone and therefore no one.'], callout: 'Anthropic builds Claude\'s core capabilities around exactly this structure: the system prompt sets Persona + standing Context; the user message provides the Task; Format is specified in whichever is most appropriate. Gemini\'s "Gems" and Google\'s Workspace AI work identically. The AI products you use every day — Copilot in Word, Gemini in Gmail, the AI tutor in your learning platform — are all professionally engineered PTFC structures. This lesson teaches you to build them yourself.' },
    { type: 'concept', title: 'PTFC in Practice: Full Worked Examples', body: 'Seeing PTFC as a complete structure — annotated by element — clarifies the framework far better than theory alone. These three prompts are written for Claude and Gemini specifically. Try pasting them in and see the difference from a vague request.', bullets: ['<strong>Claude — A-Level Essay Plan:</strong> <em>[P] You are an experienced AQA A-Level Economics examiner who marks at distinction level. [T] Analyse the impact of quantitative easing on UK inflation between 2009 and 2022, distinguishing Keynesian and monetarist interpretations. [F] Structured essay plan: thesis statement, three analytical paragraphs each with a named economist and their argument, one counter-argument paragraph, conclusion. Use bold headers. Maximum 600 words. [C] I am a Year 13 student. My examiner rewards specific named theorists and evaluative language. UK English. My weakest skill is writing counter-arguments convincingly.</em>', '<strong>Gemini Advanced — Research Briefing:</strong> <em>[P] You are a policy analyst at a parliamentary research service. [T] Synthesise key academic findings on the impact of AI on entry-level knowledge-worker jobs since 2020. [F] Structured briefing: Executive Summary (3 sentences), Key Findings (5 bullets with citations), Contested Evidence (2 bullets), Recommended Reading (3 real sources). [C] The audience is a select committee with no technical background. Avoid jargon. Flag any finding that is contested or based on limited data. Do not speculate beyond what sources support.</em>', '<strong>Claude — Revision Partner:</strong> <em>[P] You are a patient A-Level Biology tutor specialising in OCR. [T] Explain the light-dependent reactions of photosynthesis — specifically what happens to electrons in the thylakoid membrane. [F] Brief overview (2 sentences), then numbered step-by-step with maximum 2 sentences per step, then 3 self-test questions. [C] I understand covalent bonds and basic redox reactions. I always confuse Photosystem I and II. My exam is in 4 weeks. I need to understand the mechanism, not memorise it.</em>', 'Notice what Context adds: it tells Claude which exam board to calibrate vocabulary for; it tells Gemini the audience so it removes jargon; it gives the tutor-persona your exact knowledge gap. Without Context, all three prompts produce adequate generic output. With it, they produce targeted, usable responses.', '<strong>Pro tip — saving your Context:</strong> In Claude, create a Project and paste your standing Context (year group, subjects, exam boards, learning goals) into the Project instructions. Every conversation in that Project inherits it — you never re-type it. Gemini Gems works identically. This is how professionals build AI workflows that stay consistent across weeks of work.'], callout: 'Compare these to <em>"Write me an essay about QE"</em> or <em>"Explain photosynthesis."</em> The AI\'s capability is identical in both cases. The output quality difference is entirely down to the precision of your instruction. A well-built PTFC prompt from a Year 13 student will consistently outperform the average professional query.' },
    { type: 'concept', title: 'Iterating for Quality', body: 'The first output from any prompt is a draft, not a deliverable. Systematic iteration — evaluating output against your criteria and refining one element at a time — is where the real skill lies and where most beginners stop short.', bullets: ['Evaluate first: Before refining, read the output critically. What is accurate? What is too generic? What is missing? What is the wrong tone?', 'Refine one variable at a time: If you change Persona and Format simultaneously, you cannot tell which change improved the output. Change one thing, observe the effect.', 'Use follow-up prompts: "Now add a counter-argument in paragraph 2." "Make the tone more formal." "Replace the third point with a reference to Keynes." Follow-ups preserve what is working while targeting what is not.', 'Chain your prompts: Output from prompt 1 becomes input to prompt 2. "Here is a plan I generated. Now expand paragraph 3 into 200 words suitable for the exam."', 'Track everything: The Prompt Iteration Log (see Resources) records version, change, and result. This documentation is invaluable for the capstone and shows your thinking process.'], callout: 'A 2023 study found that students who iterated prompts 3+ times produced work rated 40% higher by independent markers than students who accepted the first output. The quality gap between one-shot and iterated prompting is not marginal — it is transformative.' },
    { type: 'scenario', title: 'The Vague Brief', situation: 'You are a junior content creator at a tech startup. Your manager sends you this message: "Use AI to write something about our new product launch for social media by 3pm." You have: the product name, one feature list, and access to Claude and Gemini. You have 90 minutes. Three colleagues recently got feedback that their AI content was "too generic and off-brand."', question: 'How do you use PTFC to avoid the same fate?', choices: [
      { text: 'Open Claude, paste the brief as-is and add "make it engaging" — you can always edit the output.', outcome: 'You produce a cheerful, generic product announcement that could describe any tech product. Your manager marks it as "not brand-appropriate." When asked how you made it, you struggle to explain your process. The work takes 20 minutes but the revision takes 90 more. Net result: over time and under quality.' },
      { text: 'Before prompting, ask your manager two clarifying questions: what platform is this for, and what is the brand voice? Then build a full PTFC prompt with that Context.', outcome: 'Your manager replies: LinkedIn, professional and direct, target audience is procurement managers, never use exclamation marks. You now have everything for your Context section. You paste the brand guidelines into a Claude Project instruction so they persist. The output is specific, on-brand, and needs only minor edits. Your manager asks how you got it so right on the first try. You explain PTFC. She asks you to run a team workshop on it.' },
      { text: 'Build a full PTFC prompt with a rich Context section covering brand voice, audience, and platform-specific character limits, then use Claude to produce three variants for LinkedIn, X, and Instagram simultaneously.', outcome: 'You deliver three platform-optimised variants before the deadline. Two are used without changes. Your manager forwards them to the marketing director as an example of excellent AI-assisted work. You are asked to document your prompting workflow for the team. This becomes your first piece of internal process documentation.' }
    ]},
    { type: 'activity', title: 'PTFC Challenge', instructions: 'Build, test, and systematically improve three PTFC prompts using Claude.ai or Google Gemini. Label each sentence with [P], [T], [F], or [C]. Document every version in your Prompt Iteration Log (see Resources).', steps: ['Write a PTFC prompt for: "Help me revise for my A-Level Biology exam on photosynthesis" — pay particular attention to the Context section: exam board, timeframe, your specific knowledge gaps', 'Write a PTFC prompt for: "Create a two-minute spoken debate argument against social media regulation" — think specifically about what Format a spoken argument actually requires vs a written essay', 'Write a PTFC prompt for: "Explain how gradient descent works to a Year 9 student who understands basic algebra" — the Context (prior knowledge, age group) is doing most of the work here', 'Test all three in Claude.ai or Gemini Advanced and rate each output: Accuracy (1–5), Usefulness (1–5), Tone (1–5)', 'Iterate each prompt at least twice — changing ONE element (Persona, Task, Format, or Context) each time and recording exactly what changed in the output', 'Try saving your best Persona + Context as a Claude Project instruction or Gemini Gem — share your highest-scoring prompt with the class and explain what made the Context section most effective'] },
    { type: 'discussion', title: 'The Skill of the Future?', questions: [{ num: 1, text: 'Prompt engineering jobs currently pay up to $300K+ at AI companies. Is this a durable professional skill — or will AI improve to the point where precise prompting is unnecessary?' }, { num: 2, text: 'If two students submit identical work quality but one used zero AI and one used 20 iterations of PTFC prompting — is the quality equal? Should the mark be equal?' }, { num: 3, text: 'Think of the last time you explained something to a person and they misunderstood you. How does improving your prompting make you a better communicator generally?' }] },
    { type: 'quiz', question: 'In the PTFC prompt framework, what does the "C" stand for — and why is it the element that makes the biggest difference in output quality?', options: ['Context — background that tells the AI your role, audience, purpose, prior knowledge, and constraints', 'Constraints — rules that bound the output and prevent generic responses', 'Clarity — a requirement that the output be easy to understand', 'Creativity — permission for the AI to be original and inventive'], correct: 0, explanation: 'Context is the element that transforms a generic response into a targeted one. "I am a Year 13 AQA student with 3 weeks until my exam, I always confuse Photosystems I and II, I need to understand the mechanism not memorise it" — this Context makes every other element more effective. Claude Projects and Gemini Gems both exist specifically to save and reuse your Context so you never lose it.', learnMore: 'Explore the PTFC Framework Reference Card and Prompt Iteration Log in Resources. Try Claude.ai Projects to save your exam board and year group as permanent Context — then test whether your outputs improve across a full revision session.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🏗️', label: 'PTFC transforms output', text: 'Persona + Task + Format + Context. Context is the most powerful element — it is the difference between a response for everyone and one for you.' }, { icon: '🤖', label: 'Claude and Gemini have built-in PTFC tools', text: 'Claude Projects and Gemini Gems save your Persona + Context permanently. Every session starts fully calibrated — no re-typing.' }, { icon: '🔄', label: 'Iteration is the real skill', text: 'Experts iterate 3–5 times. Students who iterate produce work rated 40% higher than those who accept the first output.' }] }
  ],

  10: [
    { type: 'hook', title: 'Synthetic Creativity & Copyright', body: 'September 2022: Jason Allen enters "Theatre D\'Opera Spatial" into the Colorado State Fair fine art competition. It wins first place. Allen had generated it using Midjourney — an AI image model. Artists were furious: "We should put a red X over all AI art." Allen replied: "I\'m not apologising for using technology." Simultaneously: Getty Images sues Stability AI for scraping 12 million copyrighted photos. The New York Times sues OpenAI for training on its journalism. Universal Music sues AI music generators. The creative industry is in open war with AI companies — and every court case is setting precedent that will shape the arts for decades.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">12M+</span><span class="sl">copyrighted images scraped by Stability AI, per lawsuit</span></div><div class="hook-stat-mini"><span class="sv">$0</span><span class="sl">paid to any artist whose work trained Midjourney</span></div><div class="hook-stat-mini"><span class="sv">2023</span><span class="sl">US Copyright Office: AI art cannot be copyrighted</span></div></div>' },
    { type: 'concept', title: 'Can AI Be Creative?', body: 'Whether AI is truly creative depends entirely on how you define creativity — and that definition has real legal, economic, and philosophical stakes. This is not an academic question: the answer determines who gets paid and who gets sued.', bullets: ['Functional creativity: AI produces novel, surprising, and valuable outputs that nobody has made before. By this definition, Midjourney is creative.', 'Intentional creativity: Genuine creativity requires intention, emotion, and a human desire to express something. AI has none of these — it optimises probability distributions.', 'Remixing vs. creating: All human creativity builds on prior work. Shakespeare borrowed plots. Picasso absorbed Cézanne. Is AI doing anything fundamentally different — or just doing it faster and at greater scale?', 'Margaret Boden\'s three types: combinational (mixing existing ideas), exploratory (working within a style), transformational (breaking the rules of a domain entirely). AI excels at the first two. The third — genuine rule-breaking — remains genuinely contested.', 'Emergent aesthetics: Some AI outputs are judged as beautiful, moving, and original by independent critics without knowing they were AI-generated. Does the judgement of the work depend on knowing its origin?'], callout: 'In 2023, the Sony World Photography Award winner Eldagsen revealed his winning photograph was AI-generated — and refused the prize to make a point about the judges\' inability to detect it. "The awarding of AI images in competitions for human photography is not the right way to deal with the AI revolution," he said. The judges agreed. The award was withdrawn.' },
    { type: 'concept', title: 'Copyright, Ownership, and the Legal Frontier', body: 'Copyright law was written in an era of human authorship. Every major AI legal case is testing assumptions that have not been challenged for 50 years — and the outcomes will reshape the creative economy.', bullets: ['US Copyright Office (2023): AI-generated images are not copyrightable. Only human authorship qualifies. Thaler v. Vidal — the AI cannot be named as an inventor on a patent or an author on a copyright.', 'The training data question: Did Stability AI commit copyright infringement by training Stable Diffusion on 5.8 billion scraped images without permission? Getty says yes. AI companies say training is transformative — like a human artist learning by studying thousands of paintings.', 'The output question: If an AI trained on Taylor Swift\'s music produces a song in her style, is that infringement? Courts have not yet ruled definitively.', 'Partial human authorship: The Copyright Office has granted copyright to AI-generated comics where a human selected and arranged the panels. The AI-generated images themselves remain unprotected. Curation is authorship.', 'Economic reality: Adobe Stock now pays contributors whose images are used to train licensed AI models. This "data dividend" model may become the standard — but most AI training happened before any such agreements existed.'], callout: 'If AI-generated content cannot be copyrighted, it enters the public domain immediately. Anyone can copy, sell, and redistribute it. This creates a paradox: the most productive creative tool in history produces outputs that nobody owns. Is that a problem or a liberation?' },
    { type: 'scenario', title: 'The Client Wants the Copyright', situation: 'You have used Midjourney to generate a series of 12 marketing illustrations for a client\'s rebrand. The brief asked for "original illustrations." The client loves the work and now wants to register copyright in the illustrations as part of their brand IP. They ask you to assign the copyright to them as part of the contract.', question: 'What do you tell the client?', choices: [
      { text: 'Sign the copyright assignment — you did the creative work of prompting and selecting the images, so the copyright is yours to assign.', outcome: 'The client registers copyright. Three months later, a competitor publishes near-identical images — Midjourney generated them from a similar prompt. The client sues for copyright infringement. During discovery, it emerges that the images were AI-generated and therefore unprotectable. The registration is invalid. The client sues you for misrepresentation and professional negligence. The contract is voided.' },
      { text: 'Explain honestly that under current UK and US law, purely AI-generated images cannot be copyrighted — the client has a licence to use them, but no exclusive ownership.', outcome: 'The client is initially disappointed. You offer a solution: you will create bespoke human-illustrated brand elements for the core logo and hero imagery, and use AI only for secondary assets. The client agrees. You charge more. The brand IP is legally protected where it matters most.' },
      { text: 'Add significant human creative elements to each image — recolouring, compositing, adding original drawn elements — to create a defensible case for partial human authorship.', outcome: 'The Copyright Office\'s current guidance suggests that where a human has made "sufficient creative contributions," copyright may attach to those contributions. You document your creative process carefully. The resulting copyright claim is partial but legitimate. The client has meaningful — if not total — IP protection. This hybrid approach becomes your standard methodology for AI illustration work.' }
    ]},
    { type: 'activity', title: 'The Copyright Court', instructions: 'Stage a mock tribunal to decide whether AI-generated art should be copyrightable, and whether training on copyrighted data constitutes infringement.', steps: ['Assign roles: Judge, AI Prompt Engineer (claimant), Human Illustrator (opposing), Stability AI Lawyer, New York Times Lawyer, UK Intellectual Property Office representative', 'Each party prepares a 2-minute opening statement — focus on one specific argument, not a general overview', 'The Judge asks each party the toughest question they face (e.g. "If training is fair use, why does it matter that the data was scraped without consent?")', 'Witnesses can be cross-examined: What counts as a "human creative contribution"? Is selection of outputs sufficient?', 'The jury (class) deliberates for 5 minutes and delivers a verdict with a written one-sentence rationale', 'After the verdict: has the law kept pace with the technology? What legislation would you draft?'] },
    { type: 'discussion', title: 'The Future of Creative Work', questions: [{ num: 1, text: 'A judge rules AI-generated art is beautiful and original but legally unprotectable because it has no human author. Should the law change to protect it — and if so, who would own it?' }, { num: 2, text: 'An artist discovers their signature painting style is now replicable by anyone typing a prompt. They lose 80% of their commercial income. What, if anything, do they deserve by way of remedy or compensation?' }, { num: 3, text: 'If AI makes professional-quality creative work essentially free to produce, what is the future of creative industries — and does it matter if fewer people earn a living from art?' }] },
    { type: 'quiz', question: 'Under current UK and US copyright law, can purely AI-generated works be copyrighted?', options: ['Yes — the AI company that built the model owns the outputs', 'Yes — the human who wrote the prompt holds copyright', 'No — copyright requires a human author', 'Only if the AI used fully licensed training data'], correct: 2, explanation: 'Both UK and US copyright law require a human author. The US Copyright Office ruled in 2023 that purely AI-generated images cannot be copyrighted — though human-curated or human-modified AI work may qualify for partial protection.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🎨', label: 'Creativity is genuinely contested', text: 'AI produces valuable, novel outputs — but lacks intention and lived experience. The definition of creativity determines the answer.' }, { icon: '⚖️', label: 'Copyright law is scrambling to catch up', text: 'AI-generated content is unprotectable. Training data lawsuits are live. The outcomes will reshape creative industries.' }, { icon: '💼', label: 'Adaptation, not just disruption', text: 'AI changes the economics of creative work profoundly — the question is how creators and industries adapt, not whether they must.' }] }
  ],

  11: [
    { type: 'hook', title: 'Deep Research & Career Disruption', body: 'In 2023, Goldman Sachs published a report that sent shockwaves through every profession: AI could automate tasks equivalent to 300 million full-time jobs globally. Legal, financial, medical, and media work — not just factories. McKinsey estimates 12 million Americans will need to change occupation by 2030. At the same time, the World Economic Forum projects AI will create 97 million new roles that do not yet exist. The net figure — 97 million new minus 85 million displaced — sounds like a gain. But it assumes the same people can make that transition. In practice, disruption is unequal, concentrated, and fast.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">300M</span><span class="sl">jobs Goldman Sachs says AI could automate</span></div><div class="hook-stat-mini"><span class="sv">97M</span><span class="sl">new roles WEF says AI will create by 2025</span></div><div class="hook-stat-mini"><span class="sv">44%</span><span class="sl">of workers\' core skills will change within 5 years (WEF)</span></div></div>Today you research what this means for the career you are planning.' },
    { type: 'video', title: 'The Rise of the Machines — Why Automation is Different this Time', videoId: 'WSKi8HfcxEk', credit: 'Kurzgesagt – In a Nutshell · 2017 · 12 min', intro: 'Why is this wave of automation different from every previous one? Kurzgesagt argues that for the first time, machines are developing "cognitive muscles" — threatening not just physical labour but intellectual work too. Watch for the key distinction between mechanical and cognitive automation, then apply it to the careers you will research today.' },
    { type: 'concept', title: 'AI-Assisted Deep Research', body: 'Deep research means going beyond the first search result to find, synthesise, and critically evaluate evidence from multiple independent sources. AI tools transform the speed of this process — but introduce new failure modes that require active mitigation.', bullets: ['AI search tools (Perplexity AI, Consensus, Elicit) can synthesise findings across thousands of academic papers in seconds', 'Hallucination risk: these tools can confidently cite studies that do not exist, misquote real researchers, or conflate separate findings', 'Recency bias: training data has cutoffs — AI tools may not know about research published in the last 6-12 months', 'Triangulation rule: confirm any AI-generated claim against at least three independent sources, including at least one primary source', 'Source hierarchy: peer-reviewed research > government/WHO reports > established journalism > AI synthesis > social media/forums'], callout: 'In 2023, a student used Perplexity to research a famous psychology study. The AI confidently stated the study had been replicated 14 times. The study had actually famously failed to replicate — it was one of the most high-profile failures in the replication crisis. The AI had learned from articles describing the original study, not from articles about its subsequent failure. Always go to the primary source.' },
    { type: 'concept', title: 'Career Disruption Patterns', body: 'AI disrupts careers in predictable patterns based on the nature of the tasks involved. Understanding these patterns early gives you a significant advantage in planning a resilient career.', bullets: ['Most at risk: routine cognitive tasks — data entry, basic financial analysis, standard legal document review, first-line customer service, radiology flagging, standard X-ray reading', 'Partially disrupted: knowledge synthesis — junior research, report writing, basic programming, paralegal work, mid-level journalism. The role survives but requires 50% fewer people.', 'Transformed: expert roles — radiologists still interpret scans, but AI does the initial sweep. Lawyers still advise, but AI reads contracts. The human does harder, more creative, higher-value work.', 'New roles emerging: AI trainers (who label data and evaluate outputs), prompt engineers, AI ethicists, AI product managers, human-AI interaction designers — most did not exist in 2020.', 'The "centaur" finding: chess players who used AI tools beat both pure AI and pure humans. Humans + AI working in tandem consistently outperform either alone.'], callout: 'The most-cited prediction failure: Geoffrey Hinton said in 2016 that AI would replace radiologists within five years. Eight years later, radiology job postings are at record highs. The job is not "reading scans" — it is diagnosing patients, communicating, managing risk, and making clinical judgements. AI handles one part. The rest is deeply human.' },
    { type: 'scenario', title: 'The Unverified Statistic', situation: 'You are writing a report for your economics class arguing that AI will create more jobs than it destroys. You ask an AI research tool for supporting evidence and it produces this: "A 2024 Oxford Economics study found that AI creates 3.2 new jobs for every job it automates, with particularly strong job growth in healthcare, education, and renewable energy sectors." The citation looks specific and credible. Your report is due in 2 hours.', question: 'What is the right approach to using this statistic?', choices: [
      { text: 'Include the citation as-is — the tool synthesises academic papers and the statistic is plausible and specific.', outcome: 'Your teacher marks the report and searches for the Oxford Economics study. It does not exist. She flags the citation as fabricated and deducts marks for academic integrity. You are required to resubmit. The experience teaches you that plausibility is not verification.' },
      { text: 'Search directly on the Oxford Economics website and in Google Scholar for the specific study before including it.', outcome: 'You find no matching study. You do find a 2023 Oxford Economics report on AI that makes more nuanced predictions — job growth is concentrated in specific sectors and dependent on policy support. This real data is actually more interesting and defensible than the fabricated statistic. Your report is better for the delay.' },
      { text: 'Rephrase the statistic as "some economists argue that AI creates more jobs than it destroys" without citing the AI-generated figure, and find at least two real sources that support this general claim.', outcome: 'You find the WEF Future of Jobs Report and a peer-reviewed Acemoglu & Restrepo paper that make this argument with proper evidence. Your report cites real research. The WEF data is actually richer than the AI-generated statistic. Your teacher notes your sourcing is unusually strong.' }
    ]},
    { type: 'activity', title: 'Research Your Future Career', instructions: 'Use AI research tools to investigate how AI will impact a career you are seriously considering — then verify every key claim.', steps: ['Choose a specific career role (not a broad field — "NHS radiographer" not "healthcare")', 'Ask Perplexity or a similar tool: "What specific tasks in this role can AI currently perform, and what is the evidence?"', 'For every statistic or study cited, spend 3 minutes trying to verify it independently — record whether you could confirm it', 'Research: What new skills or qualifications will this role require in 5 years? Find two different sources.', 'Find one real job posting for this role from the last 6 months — does it mention AI skills? What does it say?', 'Write a 200-word briefing: "If I want to enter this field in 2027, what should I be doing now, and what should I stop assuming about the role?"'] },
    { type: 'discussion', title: 'The Future of Work', questions: [{ num: 1, text: 'The "centaur" finding suggests human + AI beats both alone. Does this mean the future of work is collaboration — or that humans are temporary until AI no longer needs them?' }, { num: 2, text: 'Is it fair to say that students today have a "responsibility to AI-proof their careers" — or does this place the burden of an economic transition on individuals rather than governments and employers?' }, { num: 3, text: 'Radiologists were wrongly predicted to be automated away. What does this tell us about the limits of AI disruption predictions — and how cautious should we be about any prediction made today?' }] },
    { type: 'quiz', question: 'According to Goldman Sachs, how many full-time jobs could AI potentially automate globally?', options: ['30 million', '300 million', '3 billion', '10 billion'], correct: 1, explanation: 'Goldman Sachs estimates 300 million full-time job equivalents could be automated. However, the WEF projects 97 million new roles will emerge — the net effect depends on retraining, policy, and how quickly institutions adapt.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '📊', label: 'Disruption is real and unequal', text: '300 million jobs at risk, 97 million new roles emerging — the transition is not neutral and not automatic' }, { icon: '🔍', label: 'Always verify AI research', text: 'AI tools hallucinate specific studies and statistics. Triangulate every claim against primary sources.' }, { icon: '🤝', label: 'Centaur beats both', text: 'Humans working with AI consistently outperform either alone. The skill is knowing how to collaborate, not just delegate.' }] }
  ],

  12: [
    { type: 'hook', title: 'The Revision Loop', body: 'A 2023 study by researchers at Wharton Business School asked participants to complete a creative writing task: one group used AI with no iteration, one group iterated their prompts 3+ times, and one group wrote without AI. The findings were stark. No iteration + AI produced work rated lower than writing without AI at all. Iterating 3+ times produced work rated 40% higher than either other group. The lesson: AI without iteration makes you worse. AI with deliberate iteration makes you dramatically better.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">40%</span><span class="sl">higher quality with 3+ iterations vs no iteration</span></div><div class="hook-stat-mini"><span class="sv">Worse</span><span class="sl">than no AI at all: zero-iteration AI use</span></div><div class="hook-stat-mini"><span class="sv">3–5×</span><span class="sl">the number of prompt revisions expert engineers use</span></div></div>This lesson teaches you to use AI the way professionals do — not as an answer machine, but as a thinking partner.' },
    { type: 'concept', title: 'The Iteration Mindset', body: 'The single most important mindset shift in AI-assisted work: the first output is a draft, not a deliverable. The revision loop — Generate, Evaluate, Refine, Verify, Polish — applies whether you are writing an essay, designing a system, or building a product.', bullets: ['Generate: Use a strong PTFC prompt to produce a first draft. Record the prompt in your iteration log.', 'Evaluate: Read critically against your success criteria. Ask: Is this accurate? Analytical enough? The right tone? Missing anything essential? Rate it.', 'Refine: Give the AI one specific change at a time. "Make paragraph 2 more analytical and cite a specific economist." Specificity is everything.', 'Verify: Check every factual claim, quote, and reference independently. The revision loop does not remove the hallucination risk — it reduces it and catches what slips through.', 'Polish: Final edits in your own voice. If a sentence sounds like it was written by a chatbot, rewrite it. The output should represent your thinking, communicated in your voice.'], callout: 'Professional writers have always used this cycle. Hemingway: "The first draft of everything is garbage." The difference with AI is speed — you can complete the cycle five times in an hour instead of five days. Speed is meaningless if you stop at the first draft.' },
    { type: 'concept', title: 'AI as a Revision Partner', body: 'AI is not just a drafter — it is an exceptionally effective critic when prompted correctly. The key is asking for specific critique types, not generic improvement. These prompts work in Claude or Gemini and transform the tool into targeted editorial feedback. Try them on your next piece of coursework.', bullets: ['<strong>Structural critique (Claude):</strong> <em>"Analyse the argument structure of this essay. Identify any logical gaps, unsupported claims, or weak transitions. Do not rewrite — explain what is wrong and why, and quote the specific sentence."</em>', '<strong>Steel-manning (Claude or Gemini):</strong> <em>"What are the strongest three counter-arguments to the thesis I am making? Present them as a sceptic would, as forcefully as possible. Then suggest how I might address each."</em>', '<strong>Register check (Gemini in Docs):</strong> <em>"Rewrite this paragraph for a Year 12 reader who has not studied economics. Maintain the analytical depth but remove all jargon without explanation."</em>', '<strong>Examiner mode (Claude):</strong> <em>"Read this essay as an AQA examiner with the mark scheme in mind. What specific weaknesses would you penalise? Name the assessment objective affected for each."</em>', '<strong>Evidence gap (either tool):</strong> <em>"This paragraph makes three claims. Which one is most weakly evidenced? What type of primary source would strengthen it most?"</em>'], callout: '"Make it better" is a one-star prompt. "Act as an AQA A-Level examiner and identify the three weakest analytical moves in this essay, explain which mark band each would fall into, and quote the specific sentence that weakest" is a five-star prompt. In Claude, save your examiner Persona in a Project so you never re-specify exam board or subject — just paste in your essay.' },
    { type: 'scenario', title: 'Is It Still Yours?', situation: 'Priya has written a 1,000-word economics essay using the following process: she wrote the first draft herself (600 words, B-grade quality). She then asked Claude to identify structural weaknesses. She restructured based on that feedback. She asked for counter-arguments. She incorporated two of them. She asked for a clearer introduction. She rewrote it using the AI\'s suggestions. She then asked for evidence gaps — the AI flagged paragraph 3. She researched and added two real citations herself. The final essay is 900 words and would likely receive an A grade.', question: 'How would you characterise this piece of work, and should Priya disclose her process?', choices: [
      { text: 'This is essentially AI-generated work — Priya should not submit it without significant further rewriting of her own.', outcome: 'Priya rewrites the essay from scratch, incorporating the structural insights she gained from the AI critique process. The second attempt takes 40 minutes and produces better work than either the AI-assisted draft or her original. Using AI to understand how to improve a piece, then writing it again, is one of the most powerful learning loops available.' },
      { text: 'This is Priya\'s work, AI-assisted — the structure, arguments, and research are hers, improved by a tool. She should disclose her process as a matter of best practice.', outcome: 'Priya adds a brief methodology note: "This essay was drafted independently and refined using AI-assisted critique for structural and argumentative feedback. All factual claims were independently verified." Her teacher considers this exemplary practice. The International Baccalaureate is moving in this direction — disclosure, not prohibition.' },
      { text: 'This work is in a grey area — Priya should check her school\'s AI policy before submitting and get clarity on what is permitted.', outcome: 'Priya reads the policy. It says "AI may not be used to generate essay content." She is uncertain whether "structural feedback" counts as "generating content." She asks her teacher. The teacher says feedback and critique are fine; generating text is not. Priya\'s process was compliant, but she now understands where the line is for next time. This conversation leads the school to update their policy with clearer definitions.' }
    ]},
    { type: 'activity', title: 'The Three-Draft Challenge', instructions: 'Take a real piece of your own academic work and run it through three structured AI revision rounds. Track every change in the Prompt Iteration Log from Resources.', steps: ['Choose a paragraph or short essay you have written for any subject — something you believe is B-grade quality', 'Round 1: Ask AI to evaluate the argument structure and identify one specific weakness. Record the prompt and response.', 'Make targeted changes based on the critique. Save as Draft 2.', 'Round 2: Ask AI to identify the weakest evidenced claim and suggest what kind of source would strengthen it. Verify the suggestion.', 'Round 3: Ask AI to read it as an examiner and name the one change that would most improve the grade.', 'Compare Draft 1 and Draft 3: What changed? What is your thinking vs. the AI\'s contribution? Would you be comfortable explaining every change to your teacher?'] },
    { type: 'discussion', title: 'Authenticity and AI', questions: [{ num: 1, text: 'After four rounds of AI-assisted revision, using AI to critique structure, generate counter-arguments, improve clarity, and identify evidence gaps — is the essay still yours? At what point does the line move from "AI-assisted" to "AI-generated"?' }, { num: 2, text: 'The Wharton study shows AI without iteration makes your work worse. What does this tell us about the risk of deploying AI tools in schools without teaching students how to use them properly?' }, { num: 3, text: 'Should students be required to submit a "revision audit" showing every AI prompt and response used in producing a piece of work — and would this be practicable?' }] },
    { type: 'quiz', question: 'According to the Wharton study, how did students using AI without iteration compare to those writing without AI?', options: ['Slightly better — AI always helps even without iteration', 'About the same — AI and no-AI produced similar quality', 'Worse — zero-iteration AI use produced lower-quality work than writing without AI', 'Significantly better — any AI use improves output quality'], correct: 2, explanation: 'The Wharton study found that participants using AI without iterating their prompts produced work rated lower than those who wrote without AI. The quality gain from AI only materialises with deliberate, structured iteration — 3+ revision cycles.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🔄', label: 'Iterate or get worse', text: 'Zero-iteration AI use produces lower quality than no AI. Three+ iterations produces 40% better work. The loop is the skill.' }, { icon: '🎯', label: 'Specific critique prompts beat generic ones', text: '"Act as an examiner and find three weaknesses" beats "make it better" by a wide margin' }, { icon: '✍️', label: 'Your voice, your thinking', text: 'Every AI-revised sentence should be one you can defend, explain, and genuinely own — or rewrite it yourself.' }] }
  ]

};
